import React, { useState } from 'react';
import './ScreenThree.css';

const ScreenThree = ({ screen, formData, handleInputChange }) => {
  const [errors, setErrors] = useState({});

  const validateForm = () => {
    const newErrors = {};

    if (!formData.someField) newErrors.someField = 'This field is required';
    if (!formData.anotherField) newErrors.anotherField = 'Another field is required';
    // Add more field validations as necessary

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNextScreen = () => {
    if (validateForm()) {
      screen('screen4'); // Assuming you have a next screen to navigate to
    }
  };

  const getInputClass = (field) => (errors[field] ? 'invalid' : '');

  return (
    <div id="screen3" className="screen">
      <h1 className="title">Provide Additional Information</h1>
      <div className="answer-container">
        <div className={`answer-card ${getInputClass('someField')}`}>
          <h4>Some Field</h4>
          <input
            type="text"
            name="someField"
            value={formData.someField}
            onChange={(e) => handleInputChange('someField', e.target.value)}
          />
          {errors.someField && (
            <p className="error-message visible">{errors.someField}</p>
          )}
        </div>
        <div className={`answer-card ${getInputClass('anotherField')}`}>
          <h4>Another Field</h4>
          <input
            type="text"
            name="anotherField"
            value={formData.anotherField}
            onChange={(e) => handleInputChange('anotherField', e.target.value)}
          />
          {errors.anotherField && (
            <p className="error-message visible">{errors.anotherField}</p>
          )}
        </div>
        {/* Add more input fields as necessary */}
      </div>
      <div className="buttons">
        <button className="button-back" onClick={() => screen('screen2')}>
          Back
        </button>
        <button className="button-next" onClick={handleNextScreen}>
          Next
        </button>
      </div>
    </div>
  );
};

export default ScreenThree;
